mapper.select:


and (f.tenant_id = #{scopedTenantId})
and m.id is not null
and (m.del_flag is null or m.del_flag != 1)
and (m.is_use is null or m.is_use = '' or m.is_use != '2')

    and f.warehouse_id = #{warehouseId}


    and f.material_id = #{materialId}


    and m.name like concat('%', #{material.name}, '%')


    and (m.name like concat('%', #{materialName}, '%') or m.code like concat('%', #{materialName}, '%') or m.referred_name like concat('%', #{materialName}, '%'))


    and m.supplier_id = #{supplierId}


    and m.factory_id = #{factoryId}


    and m.storeroom_id = #{storeroomId}


    and m.is_gz = #{isGz}


    and m.is_procure = #{isProcure}


    and m.speci like concat('%', #{material.speci}, '%')

order by m.code



and f.tenant_id = #{scopedTenantId}
and f.warehouse_id = #{warehouseId}
and f.material_id = #{materialId}
